var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一個重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你決定了。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_PR`,text:{KOREA:`따뜻한 차를 내어왔습니다, 주인어른.`,JPN:` 温かいお茶をお淹れしました、社長。`,ENG:` I brought you some warm tea, Master.`,TWN:`主人，請用熱茶。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_PR`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_PR`,text:{KOREA:`각오가 어리신 그 눈빛을 보아하니, 예의 그 계약이란 것 때문에 부르신 모양이군요.`,JPN:` 覚悟のこもった目つきからすると、例の契約の件でお呼びになったようでね。`,ENG:` Judging from the determined look in your eyes, you have called me in because of the contract.`,TWN:`看主人眼中的那份堅定，應該是為那份契約而找我來的吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_PR`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_PR`,text:{KOREA:`이미 관리국에 바치기로 맹세한 몸. 이런 법률적인 절차가 무슨 의미인가 싶습니다만…`,JPN:` すでに管理局にささげることを誓った身。このような法的手続きにどういった意味があるのかと思うのですが……`,ENG:` But I have already sworn my life to the Administration, so I wonder if this legal process will matter...`,TWN:`雖然我忍不住會想，我都已發誓將要為管理局犧牲奉獻，這樣的法律程序有意義嗎…`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_PR`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_PR`,text:{KOREA:`그것이 주인어른께서 정한 방식이라면, 다시 한번 따르지 못할 것도 없지요.`,JPN:` これが社長がお決めになった流儀であるのならば、もう一度従うより他にないですね。`,ENG:` Nevertheless, if this is your decision, Master, I do not see why I should not follow.`,TWN:`不過，若這是主人決定的方式，那再遵從一次也無妨。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_PR`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};